import React, { useEffect, useState } from "react";
import {
  Box,
  Typography,
  Grid,
  Card,
  CardContent,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Button,
  CircularProgress,
  Alert,
  Tabs,
  Tab,
} from "@mui/material";
import axios from "axios";

const AdminDashboard = () => {
  const [users, setUsers] = useState([]);
  const [riders, setRiders] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [overview, setOverview] = useState({
    users: 0,
    riders: 0,
    pending: 0,
    rides: 0,
  });
  const [tab, setTab] = useState("overview");

  const token = localStorage.getItem("token");

  const fetchData = async () => {
    setLoading(true);
    setError("");
    try {
      const usersRes = await axios.get("/api/user/all", {
        headers: { Authorization: `Bearer ${token}` },
      });
      const ridersRes = await axios.get("/api/rider/all", {
        headers: { Authorization: `Bearer ${token}` },
      });
      const ridesRes = await axios.get("/api/rides/count", {
        headers: { Authorization: `Bearer ${token}` },
      });

      setUsers(usersRes.data.users || []);
      setRiders(ridersRes.data.riders || []);
      setOverview({
        users: usersRes.data.users.length || 0,
        riders: ridersRes.data.filter(r => r.status === "active").length,
        pending: ridersRes.data.filter(r => r.status === "pending").length,
        rides: ridesRes.data.count || 0,
      });
    } catch (err) {
      console.error(err);
      setError(err.response?.data?.message || "Failed to fetch data");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleApprove = async (id) => {
    try {
      await axios.post(`/api/rider/approve/${id}`, {}, {
        headers: { Authorization: `Bearer ${token}` },
      });
      fetchData();
    } catch (err) {
      console.error(err);
      setError(err.response?.data?.message || "Failed to approve rider");
    }
  };

  const handleReject = async (id) => {
    try {
      await axios.post(`/api/rider/reject/${id}`, {}, {
        headers: { Authorization: `Bearer ${token}` },
      });
      fetchData();
    } catch (err) {
      console.error(err);
      setError(err.response?.data?.message || "Failed to reject rider");
    }
  };

  return (
    <Box p={4}>
      <Typography variant="h4" gutterBottom>
        Rider App - Admin Dashboard
      </Typography>

      {/* Tabs */}
      <Tabs
        value={tab}
        onChange={(e, val) => setTab(val)}
        sx={{ mb: 3 }}
      >
        <Tab label="Overview" value="overview" />
        <Tab label="Users" value="users" />
        <Tab label="Captains" value="captains" />
        <Tab label="Pending Captains" value="pending" />
      </Tabs>

      {loading && (
        <Box display="flex" justifyContent="center" my={2}>
          <CircularProgress />
        </Box>
      )}
      {error && (
        <Alert severity="error" sx={{ mb: 2 }}>
          {error}
        </Alert>
      )}

      {/* Overview */}
      {tab === "overview" && (
        <Grid container spacing={2}>
          <Grid item xs={12} sm={6} md={3}>
            <Card>
              <CardContent>
                <Typography variant="h6">Users</Typography>
                <Typography variant="h5">{overview.users}</Typography>
              </CardContent>
            </Card>
          </Grid>
          <Grid item xs={12} sm={6} md={3}>
            <Card>
              <CardContent>
                <Typography variant="h6">Riders</Typography>
                <Typography variant="h5">{overview.riders}</Typography>
              </CardContent>
            </Card>
          </Grid>
          <Grid item xs={12} sm={6} md={3}>
            <Card>
              <CardContent>
                <Typography variant="h6">Pending</Typography>
                <Typography variant="h5">{overview.pending}</Typography>
              </CardContent>
            </Card>
          </Grid>
          <Grid item xs={12} sm={6} md={3}>
            <Card>
              <CardContent>
                <Typography variant="h6">Rides</Typography>
                <Typography variant="h5">{overview.rides}</Typography>
              </CardContent>
            </Card>
          </Grid>
        </Grid>
      )}

      {/* Users Table */}
      {tab === "users" && (
        <TableContainer component={Paper}>
          <Table>
            <TableHead>
              <TableRow>
                <TableCell><b>Full Name</b></TableCell>
                <TableCell><b>Email</b></TableCell>
                <TableCell><b>Mobile</b></TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {users.length > 0 ? users.map(u => (
                <TableRow key={u._id}>
                  <TableCell>{u.fullName}</TableCell>
                  <TableCell>{u.email}</TableCell>
                  <TableCell>{u.mobile}</TableCell>
                </TableRow>
              )) : (
                <TableRow>
                  <TableCell colSpan={3} align="center">
                    No users found
                  </TableCell>
                </TableRow>
              )}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      {/* Captains Table */}
      {tab === "captains" && (
        <TableContainer component={Paper}>
          <Table>
            <TableHead>
              <TableRow>
                <TableCell><b>Name</b></TableCell>
                <TableCell><b>Mobile</b></TableCell>
                <TableCell><b>Vehicle</b></TableCell>
                <TableCell><b>Vehicle Image</b></TableCell>
                <TableCell><b>Seating Capacity</b></TableCell>
                <TableCell><b>Color</b></TableCell>
                <TableCell><b>Documents</b></TableCell>
                <TableCell><b>Status</b></TableCell>
                <TableCell><b>Actions</b></TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {riders.length > 0 ? riders.map(r => (
                <TableRow key={r._id}>
                  <TableCell>{r.fullName}</TableCell>
                  <TableCell>{r.mobile}</TableCell>
                  <TableCell>{r.vehicle?.model || "-"}</TableCell>
                  <TableCell>
                    {r.vehicle?.image ? <img src={r.vehicle.image} alt="vehicle" width={80} /> : "-"}
                  </TableCell>
                  <TableCell>{r.vehicle?.seatingCapacity || "-"}</TableCell>
                  <TableCell>{r.vehicle?.color || "-"}</TableCell>
                  <TableCell>
                    {r.documents?.length > 0 ? r.documents.map((doc,i) => (
                      <Box key={i} mb={1}>
                        <a href={doc.url} target="_blank" rel="noreferrer">{doc.name}</a>
                      </Box>
                    )) : "-"}
                  </TableCell>
                  <TableCell>{r.status}</TableCell>
                  <TableCell>
                    {r.status === "pending" && (
                      <>
                        <Button size="small" variant="contained" color="success" sx={{mr:1}}
                          onClick={() => handleApprove(r._id)}>Approve</Button>
                        <Button size="small" variant="contained" color="error"
                          onClick={() => handleReject(r._id)}>Reject</Button>
                      </>
                    )}
                  </TableCell>
                </TableRow>
              )) : (
                <TableRow>
                  <TableCell colSpan={9} align="center">No records found</TableCell>
                </TableRow>
              )}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      {/* Pending Captains */}
      {tab === "pending" && (
        <TableContainer component={Paper}>
          <Table>
            <TableHead>
              <TableRow>
                <TableCell><b>Name</b></TableCell>
                <TableCell><b>Mobile</b></TableCell>
                <TableCell><b>Status</b></TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {riders.filter(r => r.status === "pending" || r.status === "rejected").length > 0 ? (
                riders.filter(r => r.status === "pending" || r.status === "rejected").map(r => (
                  <TableRow key={r._id}>
                    <TableCell>{r.fullName}</TableCell>
                    <TableCell>{r.mobile}</TableCell>
                    <TableCell>{r.status}</TableCell>
                  </TableRow>
                ))
              ) : (
                <TableRow>
                  <TableCell colSpan={3} align="center">No records found</TableCell>
                </TableRow>
              )}
            </TableBody>
          </Table>
        </TableContainer>
      )}
    </Box>
  );
};

export default AdminDashboard;
